import { _decorator, Component } from 'cc';
import { Symbol } from './Game_Define';
import { BaseSpine } from './Spine/BaseSpine';
import { Define, tools } from 'db://astarte-framework/utilis';
import { SpriteChange } from './Common/SpriteChange';
const { ccclass, property } = _decorator;

@ccclass('SymbolChange')
export class SymbolChange extends Component {
    //#region Properties
    @property( {
        type: SpriteChange,
        displayName: "符號 SpriteChange"
    } )
    private m_symbolSpriteChange: SpriteChange = null;

    @property( {
        type: SpriteChange,
        displayName: "最終符號 SpriteChange"
    } )
    private m_finalSymbolSpriteChange: SpriteChange = null;

    @property( {
        type: BaseSpine,
        displayName: "Wild Spine"
    } )
    private m_wildSpine: BaseSpine = null;
    //#endregion Properties

    //#region Variables
    /**@ch Wild Spine 動畫 Key*/
    private m_animKey: string = "RB_WILD_Redeem";

    /**@ch Wild Spine 動畫持續時間*/
    private m_animationDuration: number = 1.3;

    /**@ch Wild Spine 動畫速度縮放*/
    private m_animationTimeScale: number = 1.75;
    //#endregion Variables

    //#region Methods
    /**
     * @ch 播放Symbol變化動畫
     * @param symbolId 符號ID
     */
    public async PlayChangeSymbolAnimation(symbolId: number) {
        // 切換Symbol Sprite
        this.ChangeSymbolSprite(symbolId);

        // 隱藏最終Symbol Sprite
        this.m_symbolSpriteChange.node.active = true;
        this.m_finalSymbolSpriteChange.node.active = false;

        // 播放Wild Spine 動畫
        this.m_wildSpine.SetSpineNodeActivity(true);
        this.m_wildSpine.PlayAnimation(this.m_animKey, this.m_wildSpine.Spine, false, this.m_animationTimeScale);
        await Define.Wait(this, tools.strip(this.m_animationDuration / this.m_animationTimeScale));

        // 停止Wild Spine 動畫
        this.m_wildSpine.Stop();

        // 顯示最終Symbol Sprite
        this.m_wildSpine.SetSpineNodeActivity(false);
        this.m_symbolSpriteChange.node.active = false;
        this.m_finalSymbolSpriteChange.node.active = true;
    }

    /**
     * @ch 變更Symbol Sprite
     * @param symbolId 符號ID
     */
    private ChangeSymbolSprite(symbolId: number) {
        let spriteIndex = 0;
        switch (symbolId) {
            default:
            case Symbol.WildRobinHood:
                spriteIndex = 0;

                break;
            case Symbol.WildLittleJohn:
                spriteIndex = 1;

                break;
            case Symbol.WildTucker:
                spriteIndex = 2;
                break;
        }

        if (this.m_symbolSpriteChange) {
            this.m_symbolSpriteChange.ChangeSpriteByIndex(spriteIndex);
        }
        if (this.m_finalSymbolSpriteChange) {
            this.m_finalSymbolSpriteChange.ChangeSpriteByIndex(spriteIndex);
        }
    }
    //#endregion Methods
}

