1	import { _decorator, Component, Label } from 'cc';
2	import { Define } from 'db://astarte-framework/utilis';
3	import { BonusGameWinScoreItem } from './BonusGameWinScoreItem';
4	import { Common } from '../Common/Common';
5	const { ccclass, property } = _decorator;
6	
7	@ccclass('WinBoardManager')
8	export class WinBoardManager extends Component {
9	    @property({
10	        type: [BonusGameWinScoreItem],
11	        tooltip: "12個獎勵物件"
12	    })
13	    private m_winScoreItems: BonusGameWinScoreItem[] = [];
14	
15	    @property({
16	        type: Label,
17	        tooltip: "總分數顯示Label"
18	    })
19	    private m_totalBonusWinLabel: Label = null;
20	
21	    private m_itemScores: number[] = [];
22	    // 原始索引到排序後顯示位置的映射 [原始索引] = 顯示位置
23	    private m_originalIndexToDisplayIndex: number[] = [];
24	    // 排序後的分數陣列（用於查找 X 的位置）
25	    private m_sortedScores: number[] = [];
26	    // 原始索引中每個 X 是第幾個 X [原始索引] = 第幾個 X（從 1 開始，只有 X 才有值）
27	    private m_originalXOrder: number[] = [];
28	    // 排序後顯示位置中每個 X 的顯示位置索引陣列（按順序）
29	    private m_displayXIndices: number[] = [];
30	    // 記錄哪些 X 位置已經被劃掉（顯示位置索引）
31	    private m_markedXIndices: Set<number> = new Set();
32	    // 記錄每個顯示位置是否為玩家贏 [顯示位置] = true/false
33	    private m_playerWinMap: Map<number, boolean> = new Map();
34	
35	    /**
36	     * @ch 設定所有獎勵項目的分數
37	     * @param scores 分數陣列 (長度應為12)
38	     */
39	    SetItemScores(scores: number[]) {
40	        if (!scores || scores.length === 0) {
41	            return;
42	        }
43	
44	        this.m_itemScores = [...scores];
45	
46	        // 顯示順序沿用伺服器提供的順序（由上而下）
47	        this.m_originalIndexToDisplayIndex = scores.map((_, index) => index);
48	        this.m_sortedScores = [...scores];
49	
50	        // 建立原始索引中每個 X 是第幾個 X
51	        this.m_originalXOrder = new Array(scores.length).fill(0);
52	        let xOrderInOriginal = 0;
53	        for (let i = 0; i < scores.length; i++) {
54	            if (scores[i] === 0) {
55	                xOrderInOriginal++;
56	                this.m_originalXOrder[i] = xOrderInOriginal;
57	            }
58	        }
59	
60	        // 建立排序後顯示位置中所有 X 的位置索引陣列（按順序）
61	        this.m_displayXIndices = [];
62	        for (let i = 0; i < this.m_sortedScores.length; i++) {
63	            if (this.m_sortedScores[i] === 0) {
64	                this.m_displayXIndices.push(i);
65	            }
66	        }
67	
68	        // 設定排序後的分數到顯示項目
69	        for (let i = 0; i < this.m_winScoreItems.length && i < scores.length; i++) {
70	            const item = this.m_winScoreItems[i];
71	            if (item && item.isValid) {
72	                item.SetScore(scores[i]);
73	            }
74	        }
75	
76	        // 重置已標記的 X 位置和玩家贏的記錄
77	        this.m_markedXIndices.clear();
78	        this.m_playerWinMap.clear();
79	
80	        this.UpdateTotalBonusWin();
81	    }
82	
83	    /**
84	     * @ch 設定誰贏了並顯示頭像和刮痕
85	     * @param index 原始項目索引 (0-11) 或索引陣列
86	     * @param isPlayerWin true 玩家贏，false 對手贏
87	     */
88	    SetWinner(index: number | number[], isPlayerWin: boolean) {
89	        const indices = Array.isArray(index) ? index : [index];
90	        
91	        // 如果映射還沒建立，直接使用原始索引（向後兼容）
92	        if (this.m_originalIndexToDisplayIndex.length === 0) {
93	            this.SetWinnerWithoutMapping(indices, isPlayerWin);
94	            return;
95	        }
