import { _decorator, Component, Label } from 'cc';
import { Define } from 'db://astarte-framework/utilis';
import { BonusGameWinScoreItem } from './BonusGameWinScoreItem';
import { Common } from '../Common/Common';
const { ccclass, property } = _decorator;

@ccclass('WinBoardManager')
export class WinBoardManager extends Component {
    @property({
        type: [BonusGameWinScoreItem],
        tooltip: "12個獎勵物件"
    })
    private m_winScoreItems: BonusGameWinScoreItem[] = [];

    @property({
        type: Label,
        tooltip: "總分數顯示Label"
    })
    private m_totalBonusWinLabel: Label = null;

    private m_itemScores: number[] = [];
    // 原始索引到排序後顯示位置的映射 [原始索引] = 顯示位置
    private m_originalIndexToDisplayIndex: number[] = [];
    // 排序後的分數陣列（用於查找 X 的位置）
    private m_sortedScores: number[] = [];
    // 原始索引中每個 X 是第幾個 X [原始索引] = 第幾個 X（從 1 開始，只有 X 才有值）
    private m_originalXOrder: number[] = [];
    // 排序後顯示位置中每個 X 的顯示位置索引陣列（按順序）
    private m_displayXIndices: number[] = [];
    // 記錄哪些 X 位置已經被劃掉（顯示位置索引）
    private m_markedXIndices: Set<number> = new Set();
    // 記錄每個顯示位置是否為玩家贏 [顯示位置] = true/false
    private m_playerWinMap: Map<number, boolean> = new Map();

    /**
     * @ch 設定所有獎勵項目的分數
     * @param scores 分數陣列 (長度應為12)
     */
    SetItemScores(scores: number[]) {
        if (!scores || scores.length === 0) {
            return;
        }

        this.m_itemScores = [...scores];

        // 顯示順序沿用伺服器提供的順序（由上而下）
        this.m_originalIndexToDisplayIndex = scores.map((_, index) => index);
        this.m_sortedScores = [...scores];

        // 建立原始索引中每個 X 是第幾個 X
        this.m_originalXOrder = new Array(scores.length).fill(0);
        let xOrderInOriginal = 0;
        for (let i = 0; i < scores.length; i++) {
            if (scores[i] === 0) {
                xOrderInOriginal++;
                this.m_originalXOrder[i] = xOrderInOriginal;
            }
        }

        // 建立排序後顯示位置中所有 X 的位置索引陣列（按順序）
        this.m_displayXIndices = [];
        for (let i = 0; i < this.m_sortedScores.length; i++) {
            if (this.m_sortedScores[i] === 0) {
                this.m_displayXIndices.push(i);
            }
        }

        // 設定排序後的分數到顯示項目
        for (let i = 0; i < this.m_winScoreItems.length && i < scores.length; i++) {
            const item = this.m_winScoreItems[i];
            if (item && item.isValid) {
                item.SetScore(scores[i]);
            }
        }

        // 重置已標記的 X 位置和玩家贏的記錄
        this.m_markedXIndices.clear();
        this.m_playerWinMap.clear();

        this.UpdateTotalBonusWin();
    }

    /**
     * @ch 設定誰贏了並顯示頭像和刮痕
     * @param index 原始項目索引 (0-11) 或索引陣列
     * @param isPlayerWin true 玩家贏，false 對手贏
     */
    SetWinner(index: number | number[], isPlayerWin: boolean) {
        const indices = Array.isArray(index) ? index : [index];

        // 如果映射還沒建立，直接使用原始索引（向後兼容）
        if (this.m_originalIndexToDisplayIndex.length === 0) {
            this.SetWinnerWithoutMapping(indices, isPlayerWin);
            return;
        }

        for (const originalIdx of indices) {
            if (originalIdx < 0 || originalIdx >= this.m_originalIndexToDisplayIndex.length) {
                continue;
            }

