import { _decorator, Component, Node, Font } from 'cc';
import { PurseItem, PurseVisualState } from './PurseItem';

const { ccclass, property } = _decorator;

const EXPECTED_PURSE_COUNT = 12;

@ccclass('PurseManager')
export class PurseManager extends Component {
    @property({ type: Node, tooltip: '若未指定，將使用自身節點作為錢袋集合根節點' })
    private purseRoot: Node | null = null;

    @property({ type: [PurseItem], tooltip: '可選：手動指定錢袋列表（未指定時改為自動尋找）' })
    private purseItems: PurseItem[] = [];

    @property({ type: Font, tooltip: '玩家揭示時使用的數值字型 (Bonus_Fraction_Robinhood_Num)' })
    private playerAmountFont: Font | null = null;

    @property({ type: Font, tooltip: '對手揭示時使用的數值字型 (Bonus_Fraction_Littlejohn_Num)' })
    private rivalAmountFont: Font | null = null;

    @property({ tooltip: '錢袋顯示金額後自動隱藏的秒數 (0 表示不隱藏)' })
    private revealAutoHideSeconds = 1.2;

    private m_purses: PurseItem[] = [];
    private m_selectionListener: ((index: number, purse: PurseItem) => void) | null = null;
    private m_revealCompleteListener: ((index: number, purse: PurseItem) => void) | null = null;
    private readonly m_purseSelectedHandler = (purse: PurseItem) => {
        if (this.m_selectionListener) {
            this.m_selectionListener(purse.index, purse);
        }
    };
    private readonly m_purseRevealCompleteHandler = (purse: PurseItem) => {
        if (this.m_revealCompleteListener) {
            this.m_revealCompleteListener(purse.index, purse);
        }
    };

    public get Purses(): readonly PurseItem[] {
        return this.m_purses;
    }

    public get TotalPurseCount(): number {
        return this.m_purses.length;
    }


    /** 重新抓取錢袋節點列表 */
    public RefreshPurses(): void {
        if (this.purseItems && this.purseItems.length > 0) {
            this.m_purses = this.purseItems.filter((item) => !!item);
        }
        else {
            const root = this.purseRoot ?? this.node;
            this.m_purses = root.getComponentsInChildren(PurseItem);
        }
        this.SetupPurseBindings();
        this.ApplyFontsToPurses();

        if (this.m_purses.length !== EXPECTED_PURSE_COUNT) {
            console.warn(`[PurseManager] Expected ${EXPECTED_PURSE_COUNT} purses but found ${this.m_purses.length}.`);
        }
    }

    /** 重設所有錢袋為初始狀態 */
    public ResetAllPurses(): void {
        if (!this.IsPursesReady()) {
            return;
        }

        for (const purse of this.m_purses) {
            purse.ResetVisual();
            purse.SetSelectable(false);
            purse.SetAmountFonts(this.playerAmountFont, this.rivalAmountFont);
            purse.SetAutoHideDuration(this.revealAutoHideSeconds);
        }
    }

    /** 依序設定錢袋金額 */
    public SetPurseAmounts(amounts: number[]): void {
        if (!this.IsPursesReady()) {
            return;
        }

        const count = Math.min(amounts.length, this.m_purses.length);
        for (let index = 0; index < count; index += 1) {
            this.m_purses[index].SetAmount(amounts[index]);
        }
    }

    /** 揭示玩家所選錢袋結果 */
    public RevealPlayerChoice(index: number, isWin: boolean, amount: number): void {
        const target = this.GetPurse(index);
        if (!target) {
            return;
        }
        target.RevealForPlayer(isWin, amount);
    }

    /** 揭示對手所選錢袋結果 */
    public RevealRivalChoice(index: number, isWin: boolean, amount: number): void {
        const target = this.GetPurse(index);
        if (!target) {
            return;
        }
        target.RevealForRival(isWin, amount);
    }

    /** 指定錢袋狀態 */
    public SetPurseState(index: number, state: PurseVisualState): void {
        const target = this.GetPurse(index);
        if (!target) {
            return;
        }
        target.SetVisualState(state);
    }

    /** 取得指定索引的錢袋 */
    public GetPurse(index: number): PurseItem | null {
        if (!this.IsPursesReady()) {
            return null;
        }

        if (index < 0 || index >= this.m_purses.length) {
            console.warn(`[PurseManager] Purse index out of range: ${index}`);
            return null;
        }
        return this.m_purses[index];
    }

    public EnableSelection(predicate?: (purse: PurseItem, index: number) => boolean): void {
        if (!this.IsPursesReady()) {
            return;
        }
        for (const purse of this.m_purses) {
            const enable = !purse.IsRevealed && (!predicate || predicate(purse, purse.index));
            purse.SetSelectable(enable);
        }
    }

    public DisableAllSelections(): void {
        if (!this.IsPursesReady()) {
            return;
        }
        for (const purse of this.m_purses) {
            purse.SetSelectable(false);
        }
    }

    public SetSelectionListener(listener: ((index: number, purse: PurseItem) => void) | null): void {

