import { _decorator } from 'cc';
import { BaseSpine } from '../Spine/BaseSpine';
import { Define } from 'db://astarte-framework/utilis';

const { ccclass } = _decorator;

/**@en Archery Golden Wild Animation Controller @ch 射箭黃金野生動畫控制器 */
@ccclass('ArcheryCtrl')
export class ArcheryCtrl extends BaseSpine {
    /** @ch 射箭動畫 Key 常數 */
    private static readonly ANIM_KEYS = {
        inScene: 'RB_FG_M1_archery_InScene',
        standby: 'RB_FG_M1_archery_Standby',
        drawBow: 'RB_FG_M1_archery_DrawBow',
        shooting: 'RB_FG_M1_archery_Shooting',
        exit: 'RB_FG_M1_archery_Exit',
    } as const;

    /** @ch 快取的動畫時長 */
    private m_animDurations: {
        inScene: number;
        standby: number;
        drawBow: number;
        shooting: number;
        exit: number;
    } = { inScene: 0, standby: 0, drawBow: 0, shooting: 0, exit: 0.55 };

    start(): void {
        this.CacheAnimationDurations();
    }

    /**
     * @ch 快取所有射箭動畫的時長
     * @returns {void}
     */
    private CacheAnimationDurations(): void {
        const skeletonData = this.Spine.skeletonData?.getRuntimeData();
        if (!skeletonData?.animations) return;

        const getAnimDuration = (animKey: string): number => {
            return skeletonData.animations.find(anim => anim.name === animKey)?.duration ?? 0;
        };

        for (const [key, animKey] of Object.entries(ArcheryCtrl.ANIM_KEYS)) {
            const durationKey = key as keyof typeof this.m_animDurations;
            // 若已快取（> 0）則不覆蓋
            if (this.m_animDurations[durationKey] > 0) continue;
            this.m_animDurations[durationKey] = getAnimDuration(animKey);
        }
    }

    /**
     * @ch 播放射箭進場和待機動畫序列
     * @returns {Promise<void>}
     */
    public async PlayGoldenWildAnimation(): Promise<void> {
        this.SetSpineNodeActivity(true);
        this.Spine.clearTrack(0);
        this.Spine.setToSetupPose();

        // 播放動畫序列
        await this.PlayAnimation(ArcheryCtrl.ANIM_KEYS.inScene, this.Spine, false);
        // await this.PlayAnimation(ArcheryCtrl.ANIM_KEYS.standby, this.Spine, false);
        await this.PlayAnimation(ArcheryCtrl.ANIM_KEYS.drawBow, this.Spine, false);
        await this.PlayAnimation(ArcheryCtrl.ANIM_KEYS.shooting, this.Spine, false);
        this.PlayAnimation(ArcheryCtrl.ANIM_KEYS.standby, this.Spine, true);
    }

    /**
     * @ch 播放射箭退場動畫
     * @returns {Promise<void>}
     */
    public async PlayExitAnimation(): Promise<void> {
        this.PlayAnimation(ArcheryCtrl.ANIM_KEYS.exit, this.Spine, false);
        await Define.Wait(this, this.m_animDurations.exit);
        this.SetSpineNodeActivity(false);
    }

    /**
     * @ch 獲取射箭動畫的總時長
     * @param {boolean} isPlayAnim 是否計算完整播放序列的時長
     * @returns {number} 動畫時長（秒）
     */
    public GetSpineAnimDuration(isPlayAnim: boolean): number {
        if (isPlayAnim) {
            // 完整播放序列時長
            return this.m_animDurations.inScene + this.m_animDurations.drawBow + 0.5; // +1 額外延遲
        } else {
            // 退場動畫時長
            return this.m_animDurations.exit;
        }
    }
}

