/** 同步錢袋與看板的金額設定 */
public ApplyPurseAmounts(amounts: number[]): void {
    this.m_currentAmounts = [...amounts];
    this.m_purseManager?.SetPurseAmounts(this.m_currentAmounts);
    this.m_winBoardManager?.SetItemScores(this.m_currentAmounts);
    this.m_hasAppliedPurseAmounts = this.m_currentAmounts.length > 0;
}

/** 重設遊戲狀態 */
public ResetBonusGame(): void {
    this.InitializeManagers();
    this.m_pendingAction = null;
    this.m_pendingDelay = 0;
    this.m_canStartGame = false;
    this.m_hasAppliedPurseAmounts = false;
    this.m_bottomBarUpdatedPurseIndices.clear();
    this.StopAutoShootCountdown('initial');
    this.m_isAutoPlayEnabled = false;
    this.HideTimerNode();
    this.DeactivateAllCutsceneSpines(0);
    this.m_bottombarPlatform.active = false;
    this.HideFrameSpine();
    this.HideCutsceneMask();
    this.HideBonusRoot();

    // 停止 Rival 動畫輪播
    this.StopRivalPreview();

    const total = this.m_purseManager?.TotalPurseCount ?? 0;
    this.m_currentAmounts = new Array(total).fill(0);
    this.m_availableIndices = this.BuildFullIndexList();
    this.m_state = 'idle';
    this.m_activeIndex = -1;
    this.m_currentPlayerAnimation = '';
    this.m_currentPlayerLoop = false;
    this.m_currentRivalAnimation = '';
    this.m_currentRivalLoop = false;
    this.m_pendingRevealDisplayIndex = -1;
    this.m_pendingRivalRevealDisplayIndex = -1;
    this.m_playerAmounts = [];
    this.m_rivalAmounts = [];
    this.ResetRevealCursors();
    this.m_isClosingBonus = false;

    this.m_purseManager?.ResetAllPurses();
    this.m_purseManager?.DisableAllSelections();
    this.m_winBoardManager?.ResetWinners();
    if (total > 0) {
        this.m_winBoardManager?.SetItemScores(this.m_currentAmounts);
    }
    this.UpdateCharacterAnimations();
}

